<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Desktop Environment</title>
    <style>
        /* Dark theme CSS */
        body {
            background-color: #121212;
            color: #ffffff;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 0;
            padding: 20px;
        }

        /* Desktop root element */
        #desktop {
            width: 100%;
            height: 100vh;
            background-color: #1e1e1e;
            display: flex;
            justify-content: center;
            align-items: center;
            position: relative;
        }

        /* Taskbar elements */
        #taskbar {
            position: fixed;
            top: 20px;
            left: 0;
            width: 100%;
            background-color: #2d2d2d;
            padding: 10px 15px;
            z-index: 1000;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        /* Launcher buttons */
        #open-files {
            background-color: #4a4a4a;
            color: #ffffff;
            border: none;
            padding: 10px 20px;
            cursor: pointer;
            font-weight: bold;
        }
        #open-notepad {
            background-color: #3e3e3e;
            color: #ffffff;
            border: none;
            padding: 10px 20px;
            cursor: pointer;
            font-weight: bold;
        }

        /* App windows */
        #files-window, #notepad-window {
            width: 360px;
            height: 240px;
            background-color: #2d2d2d;
            border-radius: 8px;
            display: flex;
            justify-content: center;
            align-items: center;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        /* Close button */
        .win-close {
            background-color: #444;
            color: white;
            border: none;
            padding: 5px 10px;
            cursor: pointer;
            font-size: 14px;
            display: flex;
            align-items: center;
            gap: 8px;
        }

        /* File listing */
        #files-path {
            width: 100%;
            height: 300px;
            background-color: #2d2d2d;
            border-radius: 8px;
            overflow-y: auto;
            padding: 10px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        .fs-item {
            width: 100%;
            height: 150px;
            background-color: #2d2d2d;
            border-radius: 8px;
            overflow-y: auto;
            padding: 10px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        /* Tab strip */
        #tabs {
            width: 100%;
            height: 300px;
            background-color: #2d2d2d;
            border-radius: 8px;
            overflow-y: auto;
            padding: 10px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        .tab {
            width: 100%;
            height: 100%;
            background-color: #2d2d2d;
            border-radius: 8px;
            padding: 10px;
            cursor: pointer;
            font-size: 14px;
            display: flex;
            align-items: center;
            gap: 8px;
        }

        /* New tab */
        #new-tab {
            background-color: #3e3e3e;
            color: #ffffff;
            border: none;
            padding: 10px 20px;
            cursor: pointer;
            font-weight: bold;
        }

        /* Editor area */
        #editor {
            width: 100%;
            height: 300px;
            background-color: #2d2d2d;
            border-radius: 8px;
            overflow-y: auto;
            padding: 10px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }

        /* Persistent tabs */
        localStorage {
            background-color: #2d2d2d;
            color: white;
            border-radius: 8px;
            padding: 10px;
            box-shadow: 0 4px 6px rgba(0,0,0,0.3);
        }
    </style>
</head>
<body>

    <!-- Desktop root element -->
    <div id="desktop">
        <!-- Taskbar -->
        <div id="taskbar">
            <button id="open-files">#open-files</button>
            <button id="open-notepad">#open-notepad</button>
        </div>

        <!-- App windows -->
        <div id="files-window">
            <h2>Files Window</h2>
            <p>Welcome to the files directory! Click on the close button to hide this window.</p>
            <div class="win-close" onclick="hideWindow('files-window')">Close</div>
        </div>

        <div id="notepad-window">
            <h2>Notepad Window</h2>
            <p>Welcome to the notepad application! Click on the close button to hide this window.</p>
            <div class="win-close" onclick="hideWindow('notepad-window')">Close</div>
        </div>

    </div>

    <!-- File listing -->
    <div id="files-path">
        <h3>Files Listing</h3>
        <ul class="fs-item">
            <li><a href="/bin" target="_blank">bin</a></li>
            <li><a href="/etc" target="_blank">etc</a></li>
            <li><a href="/home" target="_blank">home</a></li>
            <li><a href="/usr" target="_blank">usr</a></li>
            <li><a href="/var" target="_blank">var</a></li>
        </ul>
    </div>

    <!-- Tab strip -->
    <div id="tabs">
        <div class="tab active" onclick="switchTab('new-tab')">New Tab</div>
        <div class="tab" onclick="switchTab('file1')">File 1</div>
        <div class="tab" onclick="switchTab('file2')">File 2</div>
    </div>

    <!-- Editor area -->
    <textarea id="editor"></textarea>

    <script>
        // Shell functionality
        function showWindow(windowId) {
            const element = document.getElementById(windowId);
            if (element) {
                element.style.display = 'block';
            }
        }

        function hideWindow(windowId) {
            const element = document.getElementById(windowId);
            if (element) {
                element.style.display = 'none';
            }
        }

        // File listing functionality
        window.addEventListener('click', function(event) {
            const target = event.target;
            if (target === '#files-path') {
                showWindow('files-window');
            } else if (target.classList.contains('.fs-item')) {
                const fsItem = document.querySelector(target);
                if (fsItem) {
                    // Navigate to parent or child
                    if (fsItem.parentElement && fsItem.parentElement.tagName === 'A') {
                        showWindow('files-window');
                    } else {
                        showWindow('files-path');
                    }
                }
            }
        });

        // Tab functionality
        function switchTab(tabId) {
            const tabs = document.querySelectorAll('.tab');
            let currentIndex = 0;
            for (let i = 0; i < tabs.length; i++) {
                if (tabs[i].className === tabId) {
                    currentIndex = i;
                    break;
                }
            }

            // Update active tab
            tabs[currentIndex].style.backgroundColor = '#3e3e3e';
            tabs[currentIndex].style.color = '#ffffff';

            // Create new tab if needed
            if (tabId === 'new-tab') {
                const newTab = document.createElement('div');
                newTab.className = 'tab';
                newTab.innerHTML = '<button id="new-tab">#new-tab</button>';
                tabs[currentIndex].parentElement.insertBefore(newTab, currentIndex.nextSibling);
            }

            // Update active tab's content in localStorage
            const tabContent = document.querySelector(`#${tabId}textarea`);
            if (tabContent) {
                tabContent.innerText = 'New tab selected';
            }
        }
    </script>
</body>
</html>
